public class DepositRequestRepository : IDepositRequestRepository
{
    private readonly AppDbContext _context;

    public DepositRequestRepository(AppDbContext context)
    {
        _context = context;
    }

    public async Task<DepositRequest?> GetByIdAsync(Guid requestId)
    {
        return await _context.DepositRequests
            .FirstOrDefaultAsync(d => d.Id == requestId);
    }

    public async Task AddAsync(DepositRequest request)
