    }

    public async Task<IReadOnlyList<DepositRequest>> GetByStatusAsync(DepositStatus status, int page, int pageSize)
    {
        var skip = (page - 1) * pageSize;
        
        return await _context.DepositRequests
            .Where(d => d.Status == status)
            .OrderByDescending(d => d.CreatedAt)
            .Skip(skip)
            .Take(pageSize)
            .ToListAsync();
    }

    public async Task<IReadOnlyList<DepositRequest>> GetByUserIdAsync(Guid userId, int page, int pageSize)
    {
        var skip = (page - 1) * pageSize;
        
        return await _context.DepositRequests
